Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

### Recipe

**1. Add packages to your test project**

```xml
<PackageReference Include="Microsoft.AspNetCore.Mvc.Testing" Version="9.0.*" />
<PackageReference Include="ModelContextProtocol" Version="0.2.*" />
```

**2. Wire the MCP client through the in-memory server**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using ModelContextProtocol.Client;
using ModelContextProtocol.Protocol.Transport;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>, IAsyncDisposable
{
    private readonly WebApplicationFactory<Program> _factory;
    private IMcpClient? _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _factory = factory;
    }

    private async Task<IMcpClient> GetClientAsync()
    {
        if (_client is not null) return _client;

        // The factory's HttpClient routes requests in-memory
        var httpClient = _factory.CreateDefaultClient();

        var transport = new SseClientTransport(
            new SseClientTransportOptions
            {
                Endpoint = new Uri(httpClient.BaseAddress!, "/sse"),
            },
            httpClient          // ← key: reuse the in-memory client
        );

        _client = await McpClientFactory.CreateAsync(transport);
        return _client;
    }

    [Fact]
    public async Task ListTools_ReturnsExpectedTools()
    {
        var client = await GetClientAsync();
        var tools  = await client.ListToolsAsync();

        Assert.NotEmpty(tools);
        Assert.Contains(tools, t => t.Name == "my-tool");
    }

    [Fact]
    public async Task CallTool_ReturnsResult()
    {
        var client = await GetClientAsync();
        var result = await client.CallToolAsync(
            "my-tool",
            new Dictionary<string, object?> { ["input"] = "hello" });

        Assert.False(result.IsError);
        Assert.Contains("expected-output", result.Content[0].Text);
    }

    public async ValueTask DisposeAsync()
    {
        if (_client is not null) await _client.DisposeAsync();
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` intercepts HTTP at the handler level |
| **Full protocol fidelity** | The MCP SDK's `SseClientTransport` sends real SSE/JSON-RPC — same as production |
| **Streamable HTTP** | If your server uses the newer Streamable HTTP transport, swap to `StreamableHttpClientTransport` and point `Endpoint` at `/mcp` |
| **`Program` visibility** | Expose your entry point with `[assembly: InternalsVisibleTo("YourTestProject")]` or a `public partial class Program {}` in your server |

This gives you true end-to-end MCP coverage (initialize → list → call → response) with the speed of an in-process test.
